import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { ProductProvider, useProducts } from './ProductContext';
import LandingPage from './LandingPage';
import Login from './Login';
import Register from './Register';
import Products from './Products';
import Sales from './Sales';
import History from './History';
import AddProduct from './AddProduct';
import ProductDetails from './ProductDetails';
import Admin from './Admin';

const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user } = useProducts();

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user.role)) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div className="bg-white p-8 rounded-lg shadow-md text-center">
          <h1 className="text-2xl font-bold text-red-600 mb-2">Kirish taqiqlangan!</h1>
          <p className="text-gray-600 mb-4">Ushbu sahifaga kirish uchun ruxsatingiz yo'q.</p>
          <button 
            onClick={() => window.history.back()}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
          >
            Orqaga qaytish
          </button>
        </div>
      </div>
    );
  }

  return children;
};

function App() {
  return (
    <ProductProvider>
      <Router>
        <Routes>
          <Route path="/" element={<LandingPage />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Xodim va Admin kira oladigan sahifalar */}
          <Route path="/products" element={
            <ProtectedRoute allowedRoles={['admin', 'staff']}>
              <Products />
            </ProtectedRoute>
          } />
          <Route path="/sales" element={
            <ProtectedRoute allowedRoles={['admin', 'staff']}>
              <Sales />
            </ProtectedRoute>
          } />
          <Route path="/history" element={
            <ProtectedRoute allowedRoles={['admin', 'staff']}>
              <History />
            </ProtectedRoute>
          } />
          <Route path="/product/:id" element={
            <ProtectedRoute allowedRoles={['admin', 'staff']}>
              <ProductDetails />
            </ProtectedRoute>
          } />
          <Route path="/add-product" element={
            <ProtectedRoute allowedRoles={['admin', 'staff']}>
              <AddProduct />
            </ProtectedRoute>
          } />

          {/* Faqat Admin kira oladigan sahifa */}
          <Route path="/admin" element={
            <ProtectedRoute allowedRoles={['admin']}>
              <Admin />
            </ProtectedRoute>
          } />

          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Router>
    </ProductProvider>
  );
}

export default App;
